{
  "name": "F.R.I.D.A.Y. Assistant",
  "description": "A sophisticated AI assistant inspired by Iron Man's F.R.I.D.A.Y., featuring high-performance chat, real-time voice interaction, and multi-modal capabilities.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum MessageRole {
  USER = 'user',
  FRIDAY = 'friday',
  SYSTEM = 'system'
}

export interface Message {
  id: string;
  role: MessageRole;
  text: string;
  timestamp: number;
  type?: 'text' | 'image' | 'video' | 'audio';
  mediaUrl?: string;
}

export interface VoiceState {
  isActive: boolean;
  isListening: boolean;
  isSpeaking: boolean;
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Message, MessageRole, VoiceState } from './types';
import { FRIDAY_SYSTEM_INSTRUCTION, MODELS } from './constants';
import ChatWindow from './components/ChatWindow';
import Sidebar from './components/Sidebar';
import HUDOverlay from './components/HUDOverlay';
import VoiceInterface from './components/VoiceInterface';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [voiceState, setVoiceState] = useState<VoiceState>({
    isActive: false,
    isListening: false,
    isSpeaking: false
  });

  const chatContainerRef = useRef<HTMLDivElement>(null);

  // Initialize with a welcome message
  useEffect(() => {
    const welcome: Message = {
      id: '1',
      role: MessageRole.FRIDAY,
      text: "Online and ready, Boss. All systems nominal. How can I assist you today?",
      timestamp: Date.now()
    };
    setMessages([welcome]);
  }, []);

  const handleSendMessage = async (text: string) => {
    if (!text.trim()) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: MessageRole.USER,
      text,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMessage]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: MODELS.CHAT,
        contents: text,
        config: {
          systemInstruction: FRIDAY_SYSTEM_INSTRUCTION,
          temperature: 0.7,
        },
      });

      const fridayMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: MessageRole.FRIDAY,
        text: response.text || "I'm sorry Boss, I encountered a glitch in my processors.",
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, fridayMessage]);
    } catch (error) {
      console.error("Gemini Error:", error);
      const errorMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: MessageRole.FRIDAY,
        text: "Apologies Boss, my connection to the main server is unstable. Please check your network.",
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleGenerateImage = async (prompt: string) => {
    setIsLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: MODELS.IMAGE,
        contents: { parts: [{ text: `Generate a high-tech, cinematic image: ${prompt}` }] }
      });

      let imageUrl = "";
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          imageUrl = `data:image/png;base64,${part.inlineData.data}`;
        }
      }

      if (imageUrl) {
        const imageMsg: Message = {
          id: Date.now().toString(),
          role: MessageRole.FRIDAY,
          text: `Visual rendering complete for: ${prompt}`,
          type: 'image',
          mediaUrl: imageUrl,
          timestamp: Date.now()
        };
        setMessages(prev => [...prev, imageMsg]);
      }
    } catch (error) {
      console.error("Image Generation Error:", error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="relative h-screen w-full flex overflow-hidden bg-slate-950 text-cyan-50">
      {/* Background HUD Graphics */}
      <HUDOverlay />
      <div className="scanline"></div>

      {/* Main UI Layout */}
      <Sidebar 
        isOpen={isSidebarOpen} 
        onToggle={() => setIsSidebarOpen(!isSidebarOpen)}
        onClear={() => setMessages([])}
      />

      <main className="flex-1 flex flex-col relative z-20">
        <header className="h-16 border-b border-cyan-500/20 glass flex items-center justify-between px-6">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 rounded-full border-2 border-cyan-400 flex items-center justify-center animate-pulse">
              <div className="w-4 h-4 rounded-full bg-cyan-400 shadow-[0_0_10px_#22d3ee]"></div>
            </div>
            <h1 className="orbitron font-bold text-xl tracking-widest glow-text text-cyan-400">F.R.I.D.A.Y. <span className="text-[10px] align-top text-cyan-600">OS 1.0</span></h1>
          </div>
          <div className="flex items-center gap-4 text-xs font-mono text-cyan-500/60 uppercase tracking-tighter">
            <div className="flex items-center gap-2">
              <span className="w-2 h-2 rounded-full bg-green-500"></span>
              Neural Network Active
            </div>
            <div className="hidden md:block">| GPS: 34.0195° N, 118.4912° W</div>
          </div>
        </header>

        <ChatWindow 
          messages={messages} 
          isLoading={isLoading} 
          onSendMessage={handleSendMessage}
          onGenerateImage={handleGenerateImage}
        />

        {/* Voice Interface (Floating) */}
        <VoiceInterface 
          state={voiceState}
          setState={setVoiceState}
          onTranscription={(text) => handleSendMessage(text)}
        />
      </main>

      {/* Corner HUD Data */}
      <div className="absolute bottom-4 right-4 z-50 pointer-events-none opacity-40">
        <div className="orbitron text-[8px] text-cyan-500 flex flex-col gap-1 items-end">
          <div>CPU LOAD: 14%</div>
          <div>MEM USAGE: 1.2 TB / 16 PB</div>
          <div>NET STATUS: ENCRYPTED</div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React from 'react';

const HUDOverlay: React.FC = () => {
  return (
    <div className="absolute inset-0 pointer-events-none z-0 overflow-hidden opacity-10">
      {/* Central Ring */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] border-[0.5px] border-cyan-400 rounded-full animate-pulse-slow"></div>
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] border-[1px] border-cyan-500 border-dashed rounded-full animate-[spin_60s_linear_infinite]"></div>

      {/* Grid */}
      <div className="absolute inset-0" 
           style={{ backgroundImage: 'radial-gradient(circle, #22d3ee 1px, transparent 1px)', backgroundSize: '40px 40px' }}>
      </div>

      {/* Side Decorative Lines */}
      <div className="absolute top-0 left-10 bottom-0 w-[1px] bg-gradient-to-b from-transparent via-cyan-500/50 to-transparent"></div>
      <div className="absolute top-0 right-10 bottom-0 w-[1px] bg-gradient-to-b from-transparent via-cyan-500/50 to-transparent"></div>

      {/* Corner accents */}
      <div className="absolute top-10 left-10 w-20 h-20 border-t border-l border-cyan-400"></div>
      <div className="absolute top-10 right-10 w-20 h-20 border-t border-r border-cyan-400"></div>
      <div className="absolute bottom-10 left-10 w-20 h-20 border-b border-l border-cyan-400"></div>
      <div className="absolute bottom-10 right-10 w-20 h-20 border-b border-r border-cyan-400"></div>
    </div>
  );
};

export default HUDOverlay;

import React, { useState, useRef, useEffect } from 'react';
import { Message, MessageRole } from '../types';

interface ChatWindowProps {
  messages: Message[];
  isLoading: boolean;
  onSendMessage: (text: string) => void;
  onGenerateImage: (prompt: string) => void;
}

const ChatWindow: React.FC<ChatWindowProps> = ({ messages, isLoading, onSendMessage, onGenerateImage }) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    if (input.toLowerCase().startsWith('/image ')) {
      onGenerateImage(input.slice(7));
    } else {
      onSendMessage(input);
    }
    setInput('');
  };

  return (
    <div className="flex-1 flex flex-col min-h-0 bg-black/30">
      {/* Messages Area */}
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 scrollbar-thin scrollbar-thumb-cyan-900 scrollbar-track-transparent"
      >
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex ${msg.role === MessageRole.USER ? 'justify-end' : 'justify-start'}`}
          >
            <div className={`max-w-[85%] md:max-w-[70%] group`}>
              <div className="flex items-center gap-2 mb-1 px-1">
                <span className={`text-[10px] orbitron tracking-widest uppercase ${msg.role === MessageRole.USER ? 'text-slate-400' : 'text-cyan-400'}`}>
                  {msg.role === MessageRole.USER ? 'Authorized User' : 'F.R.I.D.A.Y.'}
                </span>
                <span className="text-[9px] text-slate-600 font-mono">
                  {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </span>
              </div>

              <div className={`
                p-4 rounded-xl relative border
                ${msg.role === MessageRole.USER 
                  ? 'bg-cyan-950/40 border-cyan-700/50 text-cyan-50' 
                  : 'bg-slate-900/60 border-slate-700/50 text-slate-100'}
              `}>
                {msg.type === 'image' && msg.mediaUrl ? (
                  <div className="space-y-3">
                    <p className="text-sm whitespace-pre-wrap leading-relaxed mb-2">{msg.text}</p>
                    <div className="rounded-lg overflow-hidden border border-cyan-500/30">
                      <img src={msg.mediaUrl} alt="Generated asset" className="w-full h-auto" />
                    </div>
                  </div>
                ) : (
                  <p className="text-sm md:text-base whitespace-pre-wrap leading-relaxed">{msg.text}</p>
                )}

                {/* Visual Flair */}
                <div className={`absolute top-0 bottom-0 w-1 ${msg.role === MessageRole.USER ? 'right-0 rounded-r-xl bg-cyan-500' : 'left-0 rounded-l-xl bg-cyan-400'}`}></div>
              </div>
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-slate-900/40 border border-slate-800 p-4 rounded-xl flex items-center gap-3">
              <div className="flex space-x-1">
                <div className="w-1.5 h-1.5 bg-cyan-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                <div className="w-1.5 h-1.5 bg-cyan-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                <div className="w-1.5 h-1.5 bg-cyan-500 rounded-full animate-bounce"></div>
              </div>
              <span className="text-xs orbitron text-cyan-600 tracking-wider">Processing Data...</span>
            </div>
          </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-4 md:p-6 glass border-t border-cyan-500/20">
        <form onSubmit={handleSubmit} className="relative max-w-4xl mx-auto">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Awaiting command... (type /image for visuals)"
            className="w-full bg-slate-950/80 border border-cyan-500/30 rounded-full py-4 px-6 pr-16 text-cyan-50 focus:outline-none focus:ring-2 focus:ring-cyan-500/40 focus:border-cyan-400 transition-all placeholder:text-cyan-900 placeholder:orbitron placeholder:text-xs"
          />
          <button 
            type="submit"
            disabled={isLoading || !input.trim()}
            className="absolute right-2 top-2 bottom-2 w-12 bg-cyan-600 hover:bg-cyan-500 disabled:bg-slate-800 rounded-full flex items-center justify-center transition-colors shadow-[0_0_15px_rgba(8,145,178,0.3)]"
          >
            <i className="fa-solid fa-paper-plane text-white text-sm"></i>
          </button>
        </form>
        <div className="mt-2 text-center">
          <p className="text-[10px] text-cyan-900 orbitron uppercase tracking-[0.2em]">Secure Connection Protocol v2.4.9</p>
        </div>
      </div>
    </div>
  );
};

export default ChatWindow;

import React from 'react';

