import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Message, MessageRole, VoiceState } from './types';
import { FRIDAY_SYSTEM_INSTRUCTION, MODELS } from './constants';
import ChatWindow from './components/ChatWindow';
import Sidebar from './components/Sidebar';
import HUDOverlay from './components/HUDOverlay';
import VoiceInterface from './components/VoiceInterface';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [voiceState, setVoiceState] = useState<VoiceState>({
    isActive: false,
    isListening: false,
    isSpeaking: false
  });

  // Initialize with a welcome message
  useEffect(() => {
    const welcome: Message = {
      id: '1',
      role: MessageRole.FRIDAY,
      text: "Online and ready, Boss. All systems nominal. I'm connected to the global grid—ask me anything.",
      timestamp: Date.now()
    };
    setMessages([welcome]);
  }, []);

  const handleSendMessage = async (text: string, isFromVoice: boolean = false) => {
    if (!text.trim()) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: MessageRole.USER,
      text,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMessage]);

    // If it's a manual text message, we call the model. 
    // If it was already handled by the Voice session, we just log it.
    if (!isFromVoice) {
      setIsLoading(true);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: MODELS.CHAT,
          contents: text,
          config: {
            systemInstruction: FRIDAY_SYSTEM_INSTRUCTION,
            temperature: 0.7,
            tools: [{ googleSearch: {} }]
          },
        });

        // Extract grounding URLs if any
        const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
        const urls = chunks
          .map((chunk: any) => chunk.web?.uri)
          .filter(Boolean);

        let finalResponseText = response.text || "I'm sorry Boss, I encountered a glitch in my processors.";
        if (urls.length > 0) {
          finalResponseText += "\n\n**Sources Analyzed:**\n" + Array.from(new Set(urls)).map(url => `- ${url}`).join('\n');
        }

        const fridayMessage: Message = {
          id: (Date.now() + 1).toString(),
          role: MessageRole.FRIDAY,
          text: finalResponseText,
          timestamp: Date.now()
        };

        setMessages(prev => [...prev, fridayMessage]);
      } catch (error) {
        console.error("Gemini Error:", error);
        const errorMessage: Message = {
          id: (Date.now() + 1).toString(),
          role: MessageRole.FRIDAY,
          text: "Apologies Boss, my connection to the main server is unstable. Please check your network.",
          timestamp: Date.now()
        };
        setMessages(prev => [...prev, errorMessage]);
      } finally {
        setIsLoading(false);
      }
    }
  };

  const addFridayVoiceResponse = (text: string) => {
    const fridayMessage: Message = {
      id: Date.now().toString(),
      role: MessageRole.FRIDAY,
      text: text,
      timestamp: Date.now()
    };
    setMessages(prev => [...prev, fridayMessage]);
  };

  const handleGenerateImage = async (prompt: string) => {
    setIsLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: MODELS.IMAGE,
        contents: { parts: [{ text: `Generate a high-tech, cinematic image: ${prompt}` }] }
      });

      let imageUrl = "";
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          imageUrl = `data:image/png;base64,${part.inlineData.data}`;
        }
      }

      if (imageUrl) {
        const imageMsg: Message = {
          id: Date.now().toString(),
          role: MessageRole.FRIDAY,
          text: `Visual rendering complete for: ${prompt}`,
          type: 'image',
          mediaUrl: imageUrl,
          timestamp: Date.now()
        };
        setMessages(prev => [...prev, imageMsg]);
      }
    } catch (error) {
      console.error("Image Generation Error:", error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="relative h-screen w-full flex overflow-hidden bg-slate-950 text-cyan-50">
      <HUDOverlay />
      <div className="scanline"></div>

      <Sidebar 
        isOpen={isSidebarOpen} 
        onToggle={() => setIsSidebarOpen(!isSidebarOpen)}
        onClear={() => setMessages([])}
      />

      <main className="flex-1 flex flex-col relative z-20">
        <header className="h-16 border-b border-cyan-500/20 glass flex items-center justify-between px-6">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 rounded-full border-2 border-cyan-400 flex items-center justify-center animate-pulse">
              <div className="w-4 h-4 rounded-full bg-cyan-400 shadow-[0_0_10px_#22d3ee]"></div>
            </div>
            <h1 className="orbitron font-bold text-xl tracking-widest glow-text text-cyan-400">F.R.I.D.A.Y. <span className="text-[10px] align-top text-cyan-600">VOICE ENABLED</span></h1>
          </div>
          <div className="flex items-center gap-4 text-xs font-mono text-cyan-500/60 uppercase tracking-tighter">
            <div className="flex items-center gap-2">
              <span className={`w-2 h-2 rounded-full ${voiceState.isActive ? 'bg-cyan-400 animate-ping' : 'bg-green-500'}`}></span>
              {voiceState.isActive ? 'Audio Link Established' : 'Neural Network Active'}
            </div>
          </div>
        </header>

        <ChatWindow 
          messages={messages} 
          isLoading={isLoading} 
          onSendMessage={(text) => handleSendMessage(text, false)}
          onGenerateImage={handleGenerateImage}
        />

        <VoiceInterface 
          state={voiceState}
          setState={setVoiceState}
          onUserSpeech={(text) => handleSendMessage(text, true)}
          onFridaySpeech={(text) => addFridayVoiceResponse(text)}
        />
      </main>

      <div className="absolute bottom-4 right-4 z-50 pointer-events-none opacity-40">
        <div className="orbitron text-[8px] text-cyan-50 flex flex-col gap-1 items-end">
          <div>DATA STREAM: ACTIVE</div>
          <div>VOICE ENGINE: GEMINI 2.5</div>
        </div>
      </div>
    </div>
  );
};

