import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { VoiceState } from '../types';
import { FRIDAY_SYSTEM_INSTRUCTION, MODELS } from '../constants';

interface VoiceInterfaceProps {
  state: VoiceState;
  setState: React.Dispatch<React.SetStateAction<VoiceState>>;
  onUserSpeech: (text: string) => void;
  onFridaySpeech: (text: string) => void;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const VoiceInterface: React.FC<VoiceInterfaceProps> = ({ state, setState, onUserSpeech, onFridaySpeech }) => {
  const [session, setSession] = useState<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const streamRef = useRef<MediaStream | null>(null);

  // Transcriptions buffering
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');

  const startVoiceSession = async () => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      audioContextRef.current = outputCtx;

      const sessionPromise = ai.live.connect({
        model: MODELS.VOICE,
        callbacks: {
          onopen: () => {
            setState({ isActive: true, isListening: true, isSpeaking: false });

            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (audioProcessingEvent) => {
              const inputData = audioProcessingEvent.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };

              sessionPromise.then((activeSession) => {
                activeSession.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle transcriptions
            if (message.serverContent?.inputTranscription) {
              currentInputTranscription.current += message.serverContent.inputTranscription.text;
            }
            if (message.serverContent?.outputTranscription) {
              currentOutputTranscription.current += message.serverContent.outputTranscription.text;
            }

            if (message.serverContent?.turnComplete) {
              if (currentInputTranscription.current) {
                onUserSpeech(currentInputTranscription.current);
                currentInputTranscription.current = '';
              }
              if (currentOutputTranscription.current) {
                onFridaySpeech(currentOutputTranscription.current);
                currentOutputTranscription.current = '';
              }
            }

            const base64EncodedAudioString = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64EncodedAudioString) {
              setState(prev => ({ ...prev, isSpeaking: true }));

              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const audioBuffer = await decodeAudioData(
                decode(base64EncodedAudioString),
                outputCtx,
                24000,
                1
              );

              const source = outputCtx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outputCtx.destination);
              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) {
                  setState(prev => ({ ...prev, isSpeaking: false }));
                }
              });

              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              for (const source of sourcesRef.current.values()) {
                source.stop();
                sourcesRef.current.delete(source);
              }
              nextStartTimeRef.current = 0;
              setState(prev => ({ ...prev, isSpeaking: false }));
              currentInputTranscription.current = '';
              currentOutputTranscription.current = '';
            }
          },
          onerror: (e) => console.error("Voice Error:", e),
          onclose: () => {
            stopVoiceSession();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          systemInstruction: FRIDAY_SYSTEM_INSTRUCTION,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
          tools: [{ googleSearch: {} }]
        },
      });

      const resolvedSession = await sessionPromise;
      setSession(resolvedSession);

    } catch (err) {
      console.error("Failed to start voice:", err);
      setState({ isActive: false, isListening: false, isSpeaking: false });
    }
  };

  const stopVoiceSession = useCallback(() => {
    if (session) {
      session.close();
      setSession(null);
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setState({ isActive: false, isListening: false, isSpeaking: false });
    currentInputTranscription.current = '';
    currentOutputTranscription.current = '';
  }, [session, setState]);

  return (
    <div className="absolute bottom-24 right-8 z-50 flex flex-col items-center">
      {state.isActive && (
        <div className="mb-6 flex flex-col items-center">
          <div className="relative w-32 h-32 flex items-center justify-center">
            <div className={`absolute inset-0 rounded-full border-2 border-cyan-400/30 animate-[ping_2s_infinite] ${state.isSpeaking ? 'scale-125' : 'scale-110'}`}></div>
            <div className={`absolute inset-4 rounded-full border border-cyan-500/50 animate-[ping_3s_infinite]`}></div>

            <div className="flex items-end gap-1 h-12">
              {[1, 2, 3, 4, 5, 6, 7].map((i) => (
                <div 
                  key={i} 
                  className={`w-1.5 bg-cyan-400 rounded-full transition-all duration-150 ${state.isListening || state.isSpeaking ? 'animate-[pulse_1s_infinite]' : 'h-1'}`}
                  style={{ 
                    height: `${state.isSpeaking ? 40 + Math.random() * 60 : state.isListening ? 10 + Math.random() * 30 : 10}%`, 
                    animationDelay: `${i * 0.1}s` 
                  }}
                ></div>
              ))}
            </div>

            <div className="absolute -bottom-8 orbitron text-[10px] text-cyan-400 tracking-widest uppercase glow-text text-center w-40">
              {state.isSpeaking ? 'F.R.I.D.A.Y. Transmitting' : 'Waiting for Comm'}
            </div>
          </div>
        </div>
      )}

      <button 
        onClick={state.isActive ? stopVoiceSession : startVoiceSession}
        className={`
          w-16 h-16 rounded-full flex items-center justify-center transition-all duration-500 glass border-2
          ${state.isActive ? 'bg-cyan-500/40 border-cyan-400 shadow-[0_0_30px_rgba(34,211,238,0.6)]' : 'bg-slate-900 border-cyan-900 shadow-none'}
          hover:scale-110 active:scale-95
        `}
      >
        <i className={`fa-solid ${state.isActive ? 'fa-microphone' : 'fa-microphone-slash'} text-xl ${state.isActive ? 'text-white' : 'text-cyan-900'}`}></i>
      </button>

      <div className="mt-2 orbitron text-[8px] text-cyan-800 tracking-tighter uppercase">
        {state.isActive ? 'Encrypted Channel Open' : 'Audio Input Offline'}
      </div>
    </div>
  );
};

