import React, { useState, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Message, MessageRole, VoiceState, NeuralCore } from './types';
import { FRIDAY_SYSTEM_INSTRUCTION, CORE_CONFIGS, MODELS } from './constants';
import ChatWindow from './components/ChatWindow';
import Sidebar from './components/Sidebar';
import HUDOverlay from './components/HUDOverlay';
import VoiceInterface from './components/VoiceInterface';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [activeCore, setActiveCore] = useState<NeuralCore>('FRIDAY');
  const [voiceState, setVoiceState] = useState<VoiceState>({
    isActive: false,
    isListening: false,
    isSpeaking: false
  });

  useEffect(() => {
    const welcome: Message = {
      id: '1',
      role: MessageRole.FRIDAY,
      text: "Online and ready, Boss. All Neural Cores are standing by. Which processing unit should I initialize?",
      timestamp: Date.now(),
      core: 'FRIDAY'
    };
    setMessages([welcome]);
  }, []);

  const handleSendMessage = async (text: string, isFromVoice: boolean = false) => {
    if (!text.trim()) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: MessageRole.USER,
      text,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMessage]);

    if (!isFromVoice) {
      setIsLoading(true);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const coreConfig = CORE_CONFIGS[activeCore];

        const response = await ai.models.generateContent({
          model: MODELS.CHAT,
          contents: text,
          config: {
            systemInstruction: `${FRIDAY_SYSTEM_INSTRUCTION}\n\nACTIVE CORE PROTOCOL: ${coreConfig.instruction}`,
            temperature: 0.8,
            tools: [{ googleSearch: {} }]
          },
        });

        const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
        const urls = chunks.map((chunk: any) => chunk.web?.uri).filter(Boolean);

        let finalResponseText = response.text || "I'm sorry Boss, I encountered a glitch in my processors.";
        if (urls.length > 0) {
          finalResponseText += "\n\n**Data Sources:**\n" + Array.from(new Set(urls)).map(url => `- ${url}`).join('\n');
        }

        const fridayMessage: Message = {
          id: (Date.now() + 1).toString(),
          role: MessageRole.FRIDAY,
          text: finalResponseText,
          timestamp: Date.now(),
          core: activeCore
        };

        setMessages(prev => [...prev, fridayMessage]);
      } catch (error) {
        setMessages(prev => [...prev, {
          id: Date.now().toString(),
          role: MessageRole.FRIDAY,
          text: "Critical failure in the processing uplink. Please verify connectivity.",
          timestamp: Date.now(),
          core: 'FRIDAY'
        }]);
      } finally {
        setIsLoading(false);
      }
    }
  };

  const addFridayVoiceResponse = (text: string) => {
    setMessages(prev => [...prev, {
      id: Date.now().toString(),
      role: MessageRole.FRIDAY,
      text,
      timestamp: Date.now(),
      core: activeCore
    }]);
  };

  const handleGenerateImage = async (prompt: string) => {
    setIsLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: MODELS.IMAGE,
        contents: { parts: [{ text: `Generate a high-tech visual: ${prompt}` }] }
      });
      let imageUrl = "";
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) imageUrl = `data:image/png;base64,${part.inlineData.data}`;
      }
      if (imageUrl) {
        setMessages(prev => [...prev, {
          id: Date.now().toString(),
          role: MessageRole.FRIDAY,
          text: `Asset rendered successfully for: ${prompt}`,
          type: 'image',
          mediaUrl: imageUrl,
          timestamp: Date.now(),
          core: activeCore
        }]);
      }
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="relative h-screen w-full flex overflow-hidden bg-slate-950 text-cyan-50">
      <HUDOverlay />
      <div className="scanline"></div>

      <Sidebar 
        isOpen={isSidebarOpen} 
        onToggle={() => setIsSidebarOpen(!isSidebarOpen)}
        onClear={() => setMessages([])}
        activeCore={activeCore}
        onCoreSelect={setActiveCore}
      />

      <main className="flex-1 flex flex-col relative z-20 overflow-hidden">
        <header className="h-16 border-b border-cyan-500/20 glass flex items-center justify-between px-4 md:px-6">
          <div className="flex items-center gap-3 ml-12 lg:ml-0">
            <div className="w-7 h-7 md:w-8 md:h-8 rounded-full border-2 flex items-center justify-center animate-pulse" style={{ borderColor: CORE_CONFIGS[activeCore].color }}>
              <div className="w-3 h-3 md:w-4 md:h-4 rounded-full shadow-[0_0_10px_currentColor]" style={{ backgroundColor: CORE_CONFIGS[activeCore].color, color: CORE_CONFIGS[activeCore].color }}></div>
            </div>
            <div className="flex flex-col">
               <h1 className="orbitron font-bold text-sm md:text-base tracking-widest glow-text text-cyan-400">F.R.I.D.A.Y.</h1>
               <span className="text-[8px] md:text-[10px] orbitron font-bold tracking-tighter" style={{ color: CORE_CONFIGS[activeCore].color }}>
                 CORE: {CORE_CONFIGS[activeCore].name}
               </span>
            </div>
          </div>
          <div className="flex items-center gap-4 text-[10px] md:text-xs font-mono text-cyan-500/60 uppercase tracking-tighter">
            <div className="flex items-center gap-2">
              <span className={`w-2 h-2 rounded-full ${voiceState.isActive ? 'bg-cyan-400 animate-ping' : 'bg-green-500'}`}></span>
              <span className="hidden xs:inline">STARK_NET ACTIVE</span>
            </div>
          </div>
        </header>

        <ChatWindow 
          messages={messages} 
          isLoading={isLoading} 
          onSendMessage={(text) => handleSendMessage(text, false)}
          onGenerateImage={handleGenerateImage}
        />

        <VoiceInterface 
          state={voiceState}
          setState={setVoiceState}
          onUserSpeech={(text) => handleSendMessage(text, true)}
          onFridaySpeech={(text) => addFridayVoiceResponse(text)}
        />
      </main>
    </div>
  );
};

export default App;

