import React, { useState, useRef, useEffect } from 'react';
import { Message, MessageRole } from '../types';
import { CORE_CONFIGS } from '../constants';

interface ChatWindowProps {
  messages: Message[];
  isLoading: boolean;
  onSendMessage: (text: string) => void;
  onGenerateImage: (prompt: string) => void;
}

const ChatWindow: React.FC<ChatWindowProps> = ({ messages, isLoading, onSendMessage, onGenerateImage }) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;
    if (input.toLowerCase().startsWith('/image ')) {
      onGenerateImage(input.slice(7));
    } else {
      onSendMessage(input);
    }
    setInput('');
  };

  return (
    <div className="flex-1 flex flex-col min-h-0 bg-black/20">
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-3 md:p-6 space-y-4 md:space-y-6 scrollbar-thin scrollbar-thumb-cyan-900 scrollbar-track-transparent"
      >
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === MessageRole.USER ? 'justify-end' : 'justify-start'}`}>
            <div className="max-w-[92%] sm:max-w-[85%] md:max-w-[75%] group">
              <div className={`flex items-center gap-2 mb-1 px-1 ${msg.role === MessageRole.USER ? 'flex-row-reverse' : 'flex-row'}`}>
                <span className={`text-[9px] md:text-[10px] orbitron tracking-widest uppercase ${msg.role === MessageRole.USER ? 'text-slate-400' : 'text-cyan-400'}`}>
                  {msg.role === MessageRole.USER ? 'Boss' : 'F.R.I.D.A.Y.'}
                  {msg.core && msg.core !== 'FRIDAY' && (
                    <span className="ml-2 px-1 rounded bg-slate-800 text-[8px]" style={{ color: CORE_CONFIGS[msg.core].color }}>
                      {msg.core}
                    </span>
                  )}
                </span>
              </div>

              <div className={`
                p-3 md:p-4 rounded-xl relative border shadow-lg transition-all
                ${msg.role === MessageRole.USER 
                  ? 'bg-cyan-950/40 border-cyan-700/50 text-cyan-50 rounded-tr-none' 
                  : 'bg-slate-900/60 border-slate-700/50 text-slate-100 rounded-tl-none'}
              `}>
                {msg.type === 'image' && msg.mediaUrl ? (
                  <div className="space-y-3">
                    <p className="text-xs md:text-sm whitespace-pre-wrap leading-relaxed mb-2">{msg.text}</p>
                    <img src={msg.mediaUrl} alt="Visual" className="w-full rounded border border-cyan-500/30" />
                  </div>
                ) : (
                  <p className="text-sm md:text-base whitespace-pre-wrap leading-relaxed">{msg.text}</p>
                )}
                <div className={`absolute top-0 bottom-0 w-0.5 ${msg.role === MessageRole.USER ? 'right-0 bg-cyan-500' : 'left-0'}`}
                     style={{ backgroundColor: msg.role === MessageRole.USER ? undefined : (msg.core ? CORE_CONFIGS[msg.core].color : '#22d3ee') }}></div>
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-slate-900/40 border border-slate-800/50 p-3 rounded-xl flex items-center gap-3">
              <div className="flex space-x-1">
                <div className="w-1 h-1 bg-cyan-500 rounded-full animate-bounce"></div>
                <div className="w-1 h-1 bg-cyan-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                <div className="w-1 h-1 bg-cyan-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-3 md:p-6 glass border-t border-cyan-500/10">
        <form onSubmit={handleSubmit} className="relative max-w-4xl mx-auto flex items-center gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Initialize command sequence..."
            className="flex-1 bg-slate-900/80 border border-cyan-500/20 rounded-full py-3 px-5 text-sm text-cyan-50 focus:outline-none focus:border-cyan-400/50 transition-all placeholder:text-cyan-900/50 placeholder:orbitron placeholder:text-[9px]"
          />
          <button type="submit" disabled={isLoading} className="w-10 h-10 bg-cyan-600 rounded-full flex items-center justify-center active:scale-90 transition-transform">
            <i className="fa-solid fa-chevron-right text-white"></i>
          </button>
        </form>
      </div>
    </div>
  );
};

export default ChatWindow;

import React, { useState, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Message, MessageRole, VoiceState, NeuralCore } from './types';
import { FRIDAY_SYSTEM_INSTRUCTION, CORE_CONFIGS, MODELS } from './constants';
import ChatWindow from './components/ChatWindow';
import Sidebar from './components/Sidebar';
import HUDOverlay from './components/HUDOverlay';
import VoiceInterface from './components/VoiceInterface';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [activeCore, setActiveCore] = useState<NeuralCore>('FRIDAY');
  const [voiceState, setVoiceState] = useState<VoiceState>({
    isActive: false,
    isListening: false,
    isSpeaking: false
  });

  useEffect(() => {
    const welcome: Message = {
      id: '1',
      role: MessageRole.FRIDAY,
      text: "Online and ready, Boss. All Neural Cores are standing by. Which processing unit should I initialize?",
      timestamp: Date.now(),
      core: 'FRIDAY'
    };
    setMessages([welcome]);
  }, []);

  const handleSendMessage = async (text: string, isFromVoice: boolean = false) => {
    if (!text.trim()) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: MessageRole.USER,
      text,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMessage]);

    if (!isFromVoice) {
      setIsLoading(true);
      const fridayMessageId = (Date.now() + 1).toString();

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const coreConfig = CORE_CONFIGS[activeCore];

        const responseStream = await ai.models.generateContentStream({
          model: MODELS.CHAT,
          contents: text,
          config: {
            systemInstruction: `${FRIDAY_SYSTEM_INSTRUCTION}\n\nACTIVE CORE PROTOCOL: ${coreConfig.instruction}`,
            temperature: 0.8,
            tools: [{ googleSearch: {} }]
          },
        });

        // Initialize Friday's message with an empty string
        setMessages(prev => [...prev, {
          id: fridayMessageId,
          role: MessageRole.FRIDAY,
          text: "",
          timestamp: Date.now(),
          core: activeCore
        }]);

        let fullText = "";
        let groundingUrls: string[] = [];
        let firstChunkReceived = false;

        // Iterate through the stream chunks
        for await (const chunk of responseStream) {
          if (!firstChunkReceived) {
            // Once we have actual data, we can stop the overall "loading" dots
            setIsLoading(false);
            firstChunkReceived = true;
          }

          fullText += chunk.text || "";

          // Accumulate grounding data if present in the chunk
          const groundingMetadata = chunk.candidates?.[0]?.groundingMetadata;
          if (groundingMetadata?.groundingChunks) {
            const urls = groundingMetadata.groundingChunks
              .map((c: any) => c.web?.uri)
              .filter(Boolean);
            groundingUrls = [...new Set([...groundingUrls, ...urls])];
          }

          // Update the specific message in state line-by-line
          setMessages(prev => prev.map(m => 
            m.id === fridayMessageId ? { ...m, text: fullText } : m
          ));
        }

        // Add grounding sources at the very end if they exist
        if (groundingUrls.length > 0) {
          const sourcesText = "\n\n**Data Sources Analyzed:**\n" + Array.from(new Set(groundingUrls)).map(url => `- ${url}`).join('\n');
          setMessages(prev => prev.map(m => 
            m.id === fridayMessageId ? { ...m, text: m.text + sourcesText } : m
          ));
        }

      } catch (error) {
        console.error("Streaming Error:", error);
        setMessages(prev => {
          const exists = prev.some(m => m.id === fridayMessageId);
          if (exists) {
            return prev.map(m => m.id === fridayMessageId ? { ...m, text: "I'm sorry Boss, my connection just dropped. Please check the network uplink." } : m);
          } else {
            return [...prev, {
              id: fridayMessageId,
              role: MessageRole.FRIDAY,
              text: "Critical failure in the processing uplink. Please verify connectivity.",
              timestamp: Date.now(),
              core: 'FRIDAY'
            }];
          }
        });
      } finally {
        setIsLoading(false);
      }
    }
  };

  const addFridayVoiceResponse = (text: string) => {
    setMessages(prev => [...prev, {
      id: Date.now().toString(),
      role: MessageRole.FRIDAY,
      text,
      timestamp: Date.now(),
      core: activeCore
    }]);
  };

  const handleGenerateImage = async (prompt: string) => {
    setIsLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: MODELS.IMAGE,
        contents: { parts: [{ text: `Generate a high-tech visual: ${prompt}` }] }
      });
      let imageUrl = "";
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) imageUrl = `data:image/png;base64,${part.inlineData.data}`;
      }
      if (imageUrl) {
        setMessages(prev => [...prev, {
          id: Date.now().toString(),
          role: MessageRole.FRIDAY,
          text: `Asset rendered successfully for: ${prompt}`,
          type: 'image',
          mediaUrl: imageUrl,
          timestamp: Date.now(),
          core: activeCore
        }]);
      }
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="relative h-screen w-full flex overflow-hidden bg-slate-950 text-cyan-50">
      <HUDOverlay />
      <div className="scanline"></div>

      <Sidebar 
        isOpen={isSidebarOpen} 
        onToggle={() => setIsSidebarOpen(!isSidebarOpen)}
        onClear={() => setMessages([])}
        activeCore={activeCore}
        onCoreSelect={setActiveCore}
      />

      <main className="flex-1 flex flex-col relative z-20 overflow-hidden">
        <header className="h-16 border-b border-cyan-500/20 glass flex items-center justify-between px-4 md:px-6">
          <div className="flex items-center gap-3 ml-12 lg:ml-0">
            <div className="w-7 h-7 md:w-8 md:h-8 rounded-full border-2 flex items-center justify-center animate-pulse" style={{ borderColor: CORE_CONFIGS[activeCore].color }}>
              <div className="w-3 h-3 md:w-4 md:h-4 rounded-full shadow-[0_0_10px_currentColor]" style={{ backgroundColor: CORE_CONFIGS[activeCore].color, color: CORE_CONFIGS[activeCore].color }}></div>
            </div>
            <div className="flex flex-col">
               <h1 className="orbitron font-bold text-sm md:text-base tracking-widest glow-text text-cyan-400">F.R.I.D.A.Y.</h1>
               <span className="text-[8px] md:text-[10px] orbitron font-bold tracking-tighter" style={{ color: CORE_CONFIGS[activeCore].color }}>
                 CORE: {CORE_CONFIGS[activeCore].name}
               </span>
            </div>
          </div>
          <div className="flex items-center gap-4 text-[10px] md:text-xs font-mono text-cyan-500/60 uppercase tracking-tighter">
            <div className="flex items-center gap-2">
              <span className={`w-2 h-2 rounded-full ${voiceState.isActive ? 'bg-cyan-400 animate-ping' : 'bg-green-500'}`}></span>
              <span className="hidden xs:inline">STARK_NET ACTIVE</span>
            </div>
          </div>
        </header>

        <ChatWindow 
          messages={messages} 
          isLoading={isLoading} 
          onSendMessage={(text) => handleSendMessage(text, false)}
          onGenerateImage={handleGenerateImage}
        />

        <VoiceInterface 
          state={voiceState}
          setState={setVoiceState}
          onUserSpeech={(text) => handleSendMessage(text, true)}
          onFridaySpeech={(text) => addFridayVoiceResponse(text)}
        />
      </main>
    </div>
  );
};

export default App;

