import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { VoiceState } from '../types';
import { FRIDAY_SYSTEM_INSTRUCTION, MODELS } from '../constants';

interface VoiceInterfaceProps {
  state: VoiceState;
  setState: React.Dispatch<React.SetStateAction<VoiceState>>;
  speechRate: number;
  onUserSpeech: (text: string) => void;
  onFridaySpeech: (text: string) => void;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const VoiceInterface: React.FC<VoiceInterfaceProps> = ({ state, setState, speechRate, onUserSpeech, onFridaySpeech }) => {
  const [session, setSession] = useState<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const streamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');

  // Use a ref to always have the latest speechRate in the onmessage callback
  const speechRateRef = useRef(speechRate);
  useEffect(() => {
    speechRateRef.current = speechRate;
  }, [speechRate]);

  const stopVoiceSession = useCallback(() => {
    if (session) {
      session.close();
      setSession(null);
    }
    if (scriptProcessorRef.current) {
        scriptProcessorRef.current.disconnect();
        scriptProcessorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    if (inputContextRef.current) {
        inputContextRef.current.close();
        inputContextRef.current = null;
    }
    for (const source of sourcesRef.current.values()) {
        try { source.stop(); } catch(e) {}
    }
    sourcesRef.current.clear();

    setState({ isActive: false, isListening: false, isSpeaking: false, error: undefined });
    currentInputTranscription.current = '';
    currentOutputTranscription.current = '';
  }, [session, setState]);

  const startVoiceSession = async () => {
    setState(prev => ({ ...prev, error: undefined }));

    try {
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error("STARK_ERR: Protocol mismatch.");
      }

      let stream: MediaStream;
      try {
        stream = await navigator.mediaDevices.getUserMedia({ 
            audio: {
                echoCancellation: true,
                noiseSuppression: true,
                autoGainControl: true
            } 
        });
      } catch (err: any) {
        if (err.name === 'NotFoundError') throw new Error("STARK_ERR: Mic not found.");
        if (err.name === 'NotAllowedError') throw new Error("STARK_ERR: Access denied.");
        throw new Error("STARK_ERR: Hardware fault.");
      }

      streamRef.current = stream;
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = audioContextRef.current || new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      inputContextRef.current = inputCtx;
      audioContextRef.current = outputCtx;

      if (inputCtx.state === 'suspended') await inputCtx.resume();
      if (outputCtx.state === 'suspended') await outputCtx.resume();

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const sessionPromise = ai.live.connect({
        model: MODELS.VOICE,
        callbacks: {
          onopen: () => {
            setState({ isActive: true, isListening: true, isSpeaking: false, error: undefined });
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessorRef.current = scriptProcessor;
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const pcmBlob = { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) currentInputTranscription.current += message.serverContent.inputTranscription.text;
            if (message.serverContent?.outputTranscription) currentOutputTranscription.current += message.serverContent.outputTranscription.text;
            if (message.serverContent?.turnComplete) {
              if (currentInputTranscription.current) onUserSpeech(currentInputTranscription.current);
              if (currentOutputTranscription.current) onFridaySpeech(currentOutputTranscription.current);
              currentInputTranscription.current = '';
              currentOutputTranscription.current = '';
            }
            const base64 = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64) {
              setState(prev => ({ ...prev, isSpeaking: true }));
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outputCtx.destination);

              // Apply speech rate
              const currentRate = speechRateRef.current;
              source.playbackRate.value = currentRate;

              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setState(prev => ({ ...prev, isSpeaking: false }));
              });

              source.start(nextStartTimeRef.current);
              // Adjust start time for next chunk based on playback speed
              nextStartTimeRef.current += (audioBuffer.duration / currentRate);
              sourcesRef.current.add(source);
            }
            if (message.serverContent?.interrupted) {
              for (const s of sourcesRef.current.values()) try { s.stop(); } catch(e) {}
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setState(prev => ({ ...prev, isSpeaking: false }));
              currentInputTranscription.current = '';
              currentOutputTranscription.current = '';
            }
          },
          onerror: (e) => setState(prev => ({ ...prev, error: "STARK_ERR: Uplink failed." })),
          onclose: () => stopVoiceSession()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
          systemInstruction: FRIDAY_SYSTEM_INSTRUCTION,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
          tools: [{ googleSearch: {} }]
        }
      });
      setSession(await sessionPromise);
    } catch (err: any) {
      setState({ isActive: false, isListening: false, isSpeaking: false, error: err.message });
    }
  };

  return (
    <div className="absolute bottom-20 md:bottom-28 right-4 md:right-8 z-50 flex flex-col items-center">
      {state.error && (
        <div className="mb-3 bg-red-900/90 border border-red-500 p-2 rounded-lg text-[10px] orbitron text-red-100 max-w-[160px] md:max-w-[200px] text-center animate-pulse backdrop-blur-md">
          <i className="fa-solid fa-triangle-exclamation mr-1"></i>
          {state.error}
        </div>
      )}

      {state.isActive && !state.error && (
        <div className="mb-4 md:mb-6 flex flex-col items-center">
          <div className="relative w-24 h-24 md:w-32 md:h-32 flex items-center justify-center">
            <div className={`absolute inset-0 rounded-full border-2 border-cyan-400/30 animate-[ping_2s_infinite] ${state.isSpeaking ? 'scale-125' : 'scale-110'}`}></div>
            <div className="flex items-end gap-1 h-8 md:h-12">
              {[1, 2, 3, 4, 5, 6, 7].map((i) => (
                <div 
                  key={i} 
                  className={`w-1 md:w-1.5 bg-cyan-400 rounded-full transition-all duration-150 ${state.isListening || state.isSpeaking ? 'animate-[pulse_1s_infinite]' : 'h-1'}`}
                  style={{ 
                    height: `${state.isSpeaking ? 40 + Math.random() * 60 : state.isListening ? 10 + Math.random() * 30 : 10}%`, 
                    animationDelay: `${i * 0.1}s` 
                  }}
                ></div>
              ))}
            </div>
          </div>
        </div>
      )}

      <button 
        onClick={state.isActive ? stopVoiceSession : startVoiceSession}
        className={`
          w-12 h-12 md:w-16 md:h-16 rounded-full flex items-center justify-center transition-all duration-300 glass border-2
          ${state.error ? 'bg-red-900 border-red-500' : 
            state.isActive ? 'bg-cyan-500/40 border-cyan-400 shadow-[0_0_20px_rgba(34,211,238,0.4)]' : 
            'bg-slate-900 border-cyan-900 hover:border-cyan-400'}
          active:scale-90
        `}
      >
        <i className={`fa-solid ${state.error ? 'fa-rotate-right' : state.isActive ? 'fa-microphone' : 'fa-microphone-slash'} text-base md:text-xl ${state.error ? 'text-red-200' : state.isActive ? 'text-white' : 'text-cyan-900'}`}></i>
      </button>

      <div className="mt-2 orbitron text-[7px] md:text-[8px] text-cyan-800 tracking-tighter uppercase whitespace-nowrap">
        {state.error ? 'FAULT' : state.isActive ? 'LINK ACTIVE' : 'VOICE OFFLINE'}
      </div>
    </div>
  );
};

export default VoiceInterface;

import React, { useState, useEffect, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Message, MessageRole, VoiceState, NeuralCore } from './types';
import { FRIDAY_SYSTEM_INSTRUCTION, CORE_CONFIGS, MODELS } from './constants';
import ChatWindow from './components/ChatWindow';
import Sidebar from './components/Sidebar';
import HUDOverlay from './components/HUDOverlay';
import VoiceInterface from './components/VoiceInterface';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [activeCore, setActiveCore] = useState<NeuralCore>('FRIDAY');
  const [speechRate, setSpeechRate] = useState(1.0);
  const [voiceState, setVoiceState] = useState<VoiceState>({
    isActive: false,
    isListening: false,
    isSpeaking: false
  });

  useEffect(() => {
    const welcome: Message = {
      id: '1',
      role: MessageRole.FRIDAY,
      text: "Online and ready, Boss. All Neural Cores are standing by. Which processing unit should I initialize?",
      timestamp: Date.now(),
      core: 'FRIDAY'
    };
    setMessages([welcome]);
  }, []);

  const handleSendMessage = async (text: string, isFromVoice: boolean = false) => {
    if (!text.trim()) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: MessageRole.USER,
      text,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMessage]);

    if (!isFromVoice) {
      setIsLoading(true);
      const fridayMessageId = (Date.now() + 1).toString();

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const coreConfig = CORE_CONFIGS[activeCore];

        const responseStream = await ai.models.generateContentStream({
          model: MODELS.CHAT,
          contents: text,
          config: {
            systemInstruction: `${FRIDAY_SYSTEM_INSTRUCTION}\n\nACTIVE CORE PROTOCOL: ${coreConfig.instruction}`,
            temperature: 0.8,
            tools: [{ googleSearch: {} }]
          },
        });

        setMessages(prev => [...prev, {
          id: fridayMessageId,
          role: MessageRole.FRIDAY,
          text: "",
          timestamp: Date.now(),
          core: activeCore
        }]);

        let fullText = "";
        let groundingUrls: string[] = [];
        let firstChunkReceived = false;

        for await (const chunk of responseStream) {
          if (!firstChunkReceived) {
            setIsLoading(false);
            firstChunkReceived = true;
          }

          fullText += chunk.text || "";

          const groundingMetadata = chunk.candidates?.[0]?.groundingMetadata;
          if (groundingMetadata?.groundingChunks) {
            const urls = groundingMetadata.groundingChunks
              .map((c: any) => c.web?.uri)
              .filter(Boolean);
            groundingUrls = [...new Set([...groundingUrls, ...urls])];
          }

          setMessages(prev => prev.map(m => 
            m.id === fridayMessageId ? { ...m, text: fullText } : m
          ));
        }

        if (groundingUrls.length > 0) {
          const sourcesText = "\n\n**Data Sources Analyzed:**\n" + Array.from(new Set(groundingUrls)).map(url => `- ${url}`).join('\n');
          setMessages(prev => prev.map(m => 
            m.id === fridayMessageId ? { ...m, text: m.text + sourcesText } : m
          ));
        }

      } catch (error) {
        console.error("Streaming Error:", error);
        setMessages(prev => {
          const exists = prev.some(m => m.id === fridayMessageId);
          if (exists) {
            return prev.map(m => m.id === fridayMessageId ? { ...m, text: "I'm sorry Boss, my connection just dropped. Please check the network uplink." } : m);
          } else {
            return [...prev, {
              id: fridayMessageId,
              role: MessageRole.FRIDAY,
              text: "Critical failure in the processing uplink. Please verify connectivity.",
              timestamp: Date.now(),
              core: 'FRIDAY'
            }];
          }
        });
      } finally {
        setIsLoading(false);
      }
    }
  };

  const handleVoiceTranscriptionUpdate = useCallback((id: string, role: MessageRole, text: string) => {
    setMessages(prev => {
      const exists = prev.find(m => m.id === id);
      if (exists) {
        return prev.map(m => m.id === id ? { ...m, text } : m);
      } else {
        return [...prev, {
          id,
          role,
          text,
          timestamp: Date.now(),
          core: role === MessageRole.FRIDAY ? activeCore : undefined
        }];
      }
    });
  }, [activeCore]);

  const handleGenerateImage = async (prompt: string) => {
    setIsLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: MODELS.IMAGE,
        contents: { parts: [{ text: `Generate a high-tech visual: ${prompt}` }] }
      });
      let imageUrl = "";
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) imageUrl = `data:image/png;base64,${part.inlineData.data}`;
      }
      if (imageUrl) {
        setMessages(prev => [...prev, {
          id: Date.now().toString(),
          role: MessageRole.FRIDAY,
          text: `Asset rendered successfully for: ${prompt}`,
          type: 'image',
          mediaUrl: imageUrl,
          timestamp: Date.now(),
          core: activeCore
        }]);
      }
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="relative h-screen w-full flex overflow-hidden bg-slate-950 text-cyan-50">
      <HUDOverlay />
      <div className="scanline"></div>

      <Sidebar 
        isOpen={isSidebarOpen} 
        onToggle={() => setIsSidebarOpen(!isSidebarOpen)}
        onClear={() => setMessages([])}
        activeCore={activeCore}
        onCoreSelect={setActiveCore}
        speechRate={speechRate}
        onSpeechRateChange={setSpeechRate}
      />

      <main className="flex-1 flex flex-col relative z-20 overflow-hidden">
        <header className="h-16 border-b border-cyan-500/20 glass flex items-center justify-between px-4 md:px-6">
          <div className="flex items-center gap-3 ml-12 lg:ml-0">
            <div className="w-7 h-7 md:w-8 md:h-8 rounded-full border-2 flex items-center justify-center animate-pulse" style={{ borderColor: CORE_CONFIGS[activeCore].color }}>
              <div className="w-3 h-3 md:w-4 md:h-4 rounded-full shadow-[0_0_10px_currentColor]" style={{ backgroundColor: CORE_CONFIGS[activeCore].color, color: CORE_CONFIGS[activeCore].color }}></div>
            </div>
            <div className="flex flex-col">
               <h1 className="orbitron font-bold text-sm md:text-base tracking-widest glow-text text-cyan-400">F.R.I.D.A.Y.</h1>
               <span className="text-[8px] md:text-[10px] orbitron font-bold tracking-tighter" style={{ color: CORE_CONFIGS[activeCore].color }}>
                 CORE: {CORE_CONFIGS[activeCore].name}
               </span>
            </div>
          </div>
          <div className="flex items-center gap-4 text-[10px] md:text-xs font-mono text-cyan-500/60 uppercase tracking-tighter">
            <div className="flex items-center gap-2">
              <span className={`w-2 h-2 rounded-full ${voiceState.isActive ? 'bg-cyan-400 animate-ping' : 'bg-green-500'}`}></span>
              <span className="hidden xs:inline">STARK_NET ACTIVE</span>
            </div>
          </div>
        </header>

        <ChatWindow 
          messages={messages} 
          isLoading={isLoading} 
          onSendMessage={(text) => handleSendMessage(text, false)}
          onGenerateImage={handleGenerateImage}
        />

        <VoiceInterface 
          state={voiceState}
          setState={setVoiceState}
          speechRate={speechRate}
          onTranscriptionUpdate={handleVoiceTranscriptionUpdate}
        />
      </main>
    </div>
  );
};

